1	interface Item {
2	  type: string;
3	  material?: string;
4	  enchantment?: number;
5	  cursed?: boolean;
6	}
7	
8	interface QuoteStep {
9	  op: "quote";
10	  items: Item[];
11	}
12	
13	interface Customer {
14	  yearsWithMHPCO: number;
15	}
16	
17	interface Scenario {
18	  customer: Customer;
19	  steps: QuoteStep[];
20	}
21	
22	const COMPONENT_PREMIUM = 25;
23	const BLOCK_SIZE = 3;
24	const BLOCK_PREMIUM = 60;
25	
26	const MAIN_ITEM_PREMIUM: Record<string, number> = {
27	  sword: 100,
28	  amulet: 60,
29	  staff: 80,
30	  potion: 40,
31	};
32	
33	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
34	const CURSE_SURCHARGE_RATE = 0.5;
35	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
36	const HIGH_ENCHANTMENT_THRESHOLD = 5;
37	const LOYALTY_DISCOUNT_RATE = 0.2;
38	const LOYALTY_YEARS_THRESHOLD = 2;
39	const FOLLOWUP_DISCOUNT_RATE = 0.15;
40	const PROCESSING_FEE = 5;
41	const ROUNDING_PRECISION = 6;
42	
43	const componentBasePremium = (count: number): number => {
44	  if (count === BLOCK_SIZE) return BLOCK_PREMIUM;
45	  return count * COMPONENT_PREMIUM;
46	};
47	
48	const COMPONENT_TYPES = ["rune", "moonstone"];
49	
50	const countByType = (items: Item[]): Map<string, number> => {
51	  const counts = new Map<string, number>();
52	  for (const { type } of items) {
53	    if (COMPONENT_TYPES.includes(type)) {
54	      counts.set(type, (counts.get(type) ?? 0) + 1);
55	    }
56	  }
57	  return counts;
58	};
59	
60	const componentsBasePremium = (items: Item[]): number => {
61	  const counts = [...countByType(items).values()];
62	  return counts.reduce((total, count) => total + componentBasePremium(count), 0);
63	};
64	
65	const itemBasePremium = (item: Item): number => MAIN_ITEM_PREMIUM[item.type] ?? 0;
66	
67	const mainItemsBasePremium = (items: Item[]): number =>
68	  items.reduce((total, item) => total + itemBasePremium(item), 0);
69	
70	const policyBasePremium = (items: Item[]): number =>
71	  mainItemsBasePremium(items) + componentsBasePremium(items);
72	
73	const isHighEnchantment = (item: Item): boolean =>
74	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
75	
76	const itemSurcharge = (item: Item): number => {
77	  const base = itemBasePremium(item);
78	  const curse = item.cursed ? CURSE_SURCHARGE_RATE * base : 0;
79	  const highEnchant = isHighEnchantment(item)
80	    ? HIGH_ENCHANTMENT_SURCHARGE_RATE * base
81	    : 0;
82	  return curse + highEnchant;
83	};
84	
85	const itemSurcharges = (items: Item[]): number =>
86	  items.reduce((total, item) => total + itemSurcharge(item), 0);
87	
88	const quotePremium = (
89	  items: Item[],
90	  customer: Customer,
91	  isFollowUp: boolean,
92	): number => {
93	  const base = policyBasePremium(items);
94	  const firstInsurance = base * FIRST_INSURANCE_SURCHARGE_RATE;
95	  const loyalty =
96	    customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD
97	      ? base * LOYALTY_DISCOUNT_RATE
98	      : 0;
99	  const followUp = isFollowUp ? base * FOLLOWUP_DISCOUNT_RATE : 0;
100	  const total =
101	    base +
102	    itemSurcharges(items) +
103	    firstInsurance -
104	    loyalty -
105	    followUp +
106	    PROCESSING_FEE;
107	  return Math.ceil(Number(total.toFixed(ROUNDING_PRECISION)));
108	};
109	
110	export const runScenario = (scenario: Scenario): { results: unknown[] } => {
111	  let quoteCount = 0;
112	  const results = scenario.steps.map((step) => {
113	    const isFollowUp = quoteCount > 0;
114	    quoteCount += 1;
115	    const premium = quotePremium(step.items, scenario.customer, isFollowUp);
116	    return { premium };
117	  });
118	  return { results };
119	};
